const fs = require('fs');
// ── Machine configuration ──────────────────────────────────────────────────────────────────────────────
// Edit config.json to change paths for your machine. Do not edit this node.
const CONFIG_PATH = process.env.TAROT_CONFIG || 'D:/TarotCardProject/config.json';
// ─────────────────────────────────────────────────────────────────────────────────
const config = JSON.parse(fs.readFileSync(CONFIG_PATH, 'utf8'));

return [{ json: {
    // Machine-specific (from config.json)
    CardsDir:  config.DefaultDeckDir + '/Cards',
    OllamaAPI: config.OllamaAPI,
    // Workflow-specific
    OllamaModel:  'mistral:latest',
    SkipExisting: false,
} }];

const fs   = require('fs');
const path = require('path');

const params    = $input.first().json;
const cardsDir  = params.CardsDir;
const ollamaModel = params.OllamaModel;
const ollamaAPI   = params.OllamaAPI;
const skipExisting = !!params.SkipExisting;

const files = fs.readdirSync(cardsDir)
  .filter(f => f.endsWith('.json'))
  .sort();

if (files.length === 0) {
  throw new Error(
    `[Scan Card Files] No JSON files found in ${cardsDir}. ` +
    'Check that CardsDir is correct.'
  );
}

console.log(`[Scan Card Files] Found ${files.length} card files in ${cardsDir}`);

return files.map(f => {
  const fullPath = path.join(cardsDir, f);
  const resolved = path.resolve(fullPath);
  const resolvedDir = path.resolve(cardsDir);
  if (!resolved.startsWith(resolvedDir + path.sep) && resolved !== resolvedDir) {
    throw new Error('[Scan Card Files] Path traversal detected: ' + f);
  }
  return { json: {
    FilePath:     fullPath,
    FileName:     f,
    OllamaModel:  ollamaModel,
    OllamaAPI:    ollamaAPI,
    SkipExisting: skipExisting
  } };
});

const http  = require('http');
const https = require('https');
const fs    = require('fs');
const path  = require('path');

const httpRequest = (method, urlStr, body) => new Promise((resolve, reject) => {
  const m = urlStr.match(/^(https?):/\/([^:/]+)(?::(\d+))?(\/?[^?]*)(\?.*)?$/);
  const protocol = m[1], hostname = m[2];
  const port = m[3] ? parseInt(m[3]) : (protocol === 'https' ? 443 : 80);
  const pathPart = (m[4] || '/') + (m[5] || '');
  const lib = protocol === 'https' ? https : http;
  const options = { hostname, port, path: pathPart, method, headers: {} };
  if (body) {
    options.headers['Content-Type'] = 'application/json';
    options.headers['Content-Length'] = Buffer.byteLength(body);
  }
  const req = lib.request(options, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve(data); } });
  });
  req.on('error', reject);
  if (body) req.write(body);
  req.end();
});
const httpPost = (url, bodyObj) => httpRequest('POST', url, JSON.stringify(bodyObj));
const httpGet = (url) => httpRequest('GET', url, null);

const allItems   = $input.all().map(i => i.json);
const ollamaAPI  = allItems[0].OllamaAPI;
const ollamaModel = allItems[0].OllamaModel;
const skipExisting = allItems[0].SkipExisting;

const sleep = ms => new Promise(r => setTimeout(r, ms));
const results = [];
const errors  = [];

// Allowed Voice values — must match Deck.json Prompts.Narration.VoiceMap keys
const VALID_VOICES = [
  'Female', 'Male', 'Neutral',
  'Young Female', 'Young Male',
  'Mature Female', 'Mature Male',
  'Warm Female', 'Mystical', 'Authoritative'
];

// Generic placeholder values written by previous tooling — treat as absent
const GENERIC_VOICE = 'Female';
const GENERIC_TONE  = 'Warm and uplifting';
const GENERIC_PACE  = 'Moderate';

for (const item of allItems) {
  const { FilePath, FileName } = item;

  // --- Read card JSON ---
  let cardData;
  try {
    cardData = JSON.parse(fs.readFileSync(FilePath, 'utf8'));
  } catch (e) {
    errors.push({ file: FileName, error: 'Read/parse error: ' + e.message });
    console.warn(`[Gen Narration] Read error ${FileName}: ${e.message}`);
    continue;
  }

  const cardMeta = cardData['data.Cards'];
  if (!cardMeta || !Array.isArray(cardMeta.records)) {
    errors.push({ file: FileName, error: 'No data.Cards.records array' });
    console.warn(`[Gen Narration] No records in ${FileName}`);
    continue;
  }

  const cardName = cardMeta.Card || FileName.replace(/\.json$/, '').replace(/_/g, ' ');
  let updatedCount = 0;

  for (const record of cardMeta.records) {
    const orientation = record.Orientation || '(unknown)';
    const ci          = record.Prompts?.CharacterImage || {};
    const positivePrompt = (ci.Positive || '').trim();
    const charName       = (ci.CharacterName || '').trim();

    if (!positivePrompt) {
      console.warn(`[Gen Narration] No Positive prompt for ${cardName}/${orientation} — skipping`);
      continue;
    }

    // --- Skip if all fields already populated and non-generic (when SkipExisting=true) ---
    if (skipExisting) {
      const narr = record.Prompts?.Narration || {};
      const allFilled =
        narr.Voice      && narr.Voice      !== GENERIC_VOICE &&
        narr.Tone       && narr.Tone       !== GENERIC_TONE  &&
        narr.Pace       && narr.Pace       !== GENERIC_PACE  &&
        narr.Emphasis   && narr['De-emphasis'];
      if (allFilled) {
        console.log(`[Gen Narration] ${cardName}/${orientation}: already has custom values, skipping`);
        continue;
      }
    }

    // --- Build Ollama prompt ---
    const userPrompt = [
      'You are a tarot card narrator style advisor.',
      '',
      'Given this character image for a tarot card:',
      `  Card:        ${cardName}`,
      `  Orientation: ${orientation}`,
      `  Character:   ${charName}`,
      `  Image cues:  ${positivePrompt}`,
      '',
      'Determine the most fitting narration style for reading this card aloud.',
      'Respond with valid JSON only — no markdown, no extra text.',
      'Use exactly these fields:',
      '{',
      '  "Voice": "one of exactly: Female | Male | Neutral | Young Female | Young Male | Mature Female | Mature Male | Warm Female | Mystical | Authoritative",',
      '  "Tone": "2–5 word emotional tone suited to this card and orientation (e.g. Warm and uplifting / Mysterious and Kind / Somber and reflective / Bold and inspiring)",',
      '  "Pace": "one of exactly: Slow | Moderate | Brisk",',
      '  "Emphasis": "One sentence: what themes or imagery to highlight when narrating this card",',
      '  "De-emphasis": "One sentence: what to avoid over-emphasising for this card in this orientation"',
      '}'
    ].join('\n');

    // --- Call Ollama ---
    let parsed;
    try {
      const resp = await httpPost(
        ollamaAPI + '/api/generate',
        {
          model:  ollamaModel,
          prompt: userPrompt,
          stream: false,
          format: 'json',
          options: { temperature: 0.3, num_predict: 300 }
        }
      );

      const raw = (resp.response || '').trim();
      try {
        parsed = JSON.parse(raw);
      } catch (e) {
        console.warn(`[Gen Narration] JSON parse failed for ${cardName}/${orientation}: ${raw.substring(0, 120)}`);
        errors.push({ file: FileName, card: cardName, orientation, error: 'JSON parse: ' + e.message });
        continue;
      }
    } catch (e) {
      console.warn(`[Gen Narration] Ollama error for ${cardName}/${orientation}: ${e.message}`);
      errors.push({ file: FileName, card: cardName, orientation, error: 'Ollama: ' + e.message });
      continue;
    }

    // --- Validate and normalise Voice ---
    let voice = (parsed.Voice || '').trim();
    if (!VALID_VOICES.includes(voice)) {
      // Try case-insensitive match
      const match = VALID_VOICES.find(v => v.toLowerCase() === voice.toLowerCase());
      if (match) {
        voice = match;
      } else {
        console.warn(`[Gen Narration] Invalid Voice "${voice}" for ${cardName}/${orientation} — defaulting to Female`);
        voice = 'Female';
      }
    }

    // --- Validate Pace ---
    let pace = (parsed.Pace || '').trim();
    if (!['Slow', 'Moderate', 'Brisk'].includes(pace)) {
      console.warn(`[Gen Narration] Invalid Pace "${pace}" for ${cardName}/${orientation} — defaulting to Moderate`);
      pace = 'Moderate';
    }

    // --- Merge into record (preserve Volume, Style, Content) ---
    if (!record.Prompts)          record.Prompts = {};
    if (!record.Prompts.Narration) record.Prompts.Narration = {};

    record.Prompts.Narration.Voice          = voice;
    record.Prompts.Narration.Tone           = (parsed.Tone         || '').trim() || record.Prompts.Narration.Tone;
    record.Prompts.Narration.Pace           = pace;
    record.Prompts.Narration.Emphasis       = (parsed.Emphasis     || '').trim() || record.Prompts.Narration.Emphasis;
    record.Prompts.Narration['De-emphasis'] = (parsed['De-emphasis'] || '').trim() || record.Prompts.Narration['De-emphasis'];

    updatedCount++;
    console.log(`[Gen Narration] ${cardName}/${orientation}: Voice=${voice}, Tone=${record.Prompts.Narration.Tone}, Pace=${pace}`);
  }

  // --- Write updated card JSON back to disk ---
  try {
    fs.writeFileSync(FilePath, JSON.stringify(cardData, null, 2), 'utf8');
    results.push({ card: cardName, file: FileName, updated: updatedCount });
    console.log(`[Gen Narration] Written ${FileName} (${updatedCount} records updated)`);
  } catch (e) {
    errors.push({ file: FileName, card: cardName, error: 'Write error: ' + e.message });
    console.warn(`[Gen Narration] Write error ${FileName}: ${e.message}`);
  }
}

if (results.length === 0 && errors.length > 0) {
  throw new Error(
    `[Gen Narration] All ${errors.length} cards failed. First: ` +
    `${errors[0].card || errors[0].file} — ${errors[0].error}`
  );
}

if (errors.length > 0) {
  console.warn(`[Gen Narration] ${errors.length} record errors across ${results.length} cards`);
}

return [...results, ...errors].map(r => ({ json: r }));

const all       = $input.all().map(i => i.json);
const succeeded = all.filter(j => !j.error && j.updated !== undefined);
const failed    = all.filter(j =>  j.error);

const totalRecords = succeeded.reduce((s, j) => s + (j.updated || 0), 0);

console.log(
  `[Report] Done: ${succeeded.length} cards processed (${totalRecords} records updated), ` +
  `${failed.length} errors`
);

if (failed.length > 0) {
  console.warn('[Report] Errors:');
  for (const f of failed) {
    console.warn(`  ${f.card || f.file}: ${f.error}`);
  }
}

return [{
  json: {
    cardsProcessed:  succeeded.length,
    recordsUpdated:  totalRecords,
    errorCount:      failed.length,
    errors: failed.map(f => ({ card: f.card || f.file, orientation: f.orientation, error: f.error }))
  }
}];
